import React, { use } from 'react';
import { useState } from 'react';
import Piece from './piece';
import { piece } from '../types/piece';


export default function Chessboard() {
    const [posibleMoves, setPosibleMoves] = useState(new Set<string>());
    
    const size = 8; 
    let chessboard: (piece | null)[][] = Array.from({ length: size }, () => Array(size).fill(null));
    chessboard[1][3] = { position: { row: 1, col: 3 }, image: '/Chess_plt45.svg', type: 'pawn', posibleMoves: [{ dx: 0, dy: 1, repeat: false }, { dx: 0, dy: 1, repeat: false }] }; 
    
    function handleSquareClick(piecePosition: piece | null) {
        if (piecePosition) {
            piecePosition.posibleMoves.forEach(move => {
                const r = piecePosition.position.row + move.dy;
                const c = piecePosition.position.col + move.dx;
                if (r >= 0 && r < size && c >= 0 && c < size) {
                    posibleMoves.add(`${r},${c}`);
                }
            });
        }
        return;
        
    }
    
    return (
        <div className="chessboard">
           {Array.from({ length: size }).map((_, row) => (
                <div key={row} className="flex">
                    {Array.from({ length: size }).map((_, col) => {
                        const isWhite = (row + col) % 2 === 0;
                        const posKey = `${row},${col}`;
                        const isHighlighted = posibleMoves.has(posKey);
                        return (
                            <div
                                key={col}
                                className={`chessboard-square-${row}-${col} ${isWhite ? 'bg-white' : 'bg-purple-900'} w-24 h-24 flex items-center justify-center`}
                                onClick={() => handleSquareClick(chessboard[row][col])}
                            >
                                {chessboard[row][col] && (
                                    <Piece image={chessboard[row][col].image} position={chessboard[row][col].position} type={chessboard[row][col].type} posibleMoves={chessboard[row][col].posibleMoves} chessboard={chessboard} />
                                ) || (
                                    <div className={`w-8 h-8 rounded-full bg-gray-400 opacity-40 ${isHighlighted ? 'block' : 'hidden'}`}></div>
                                )}

                            </div>
                        );
                    })}
                </div>
            ))}
        </div>
    )
}